        # (-total_score, -gameplay_points, -unique_platforms, submission_timestamp)
        return (-r[0], -r[1], -r[2], r[3])

    for prev, nxt in zip(o, o[1:]):
        if rank_key(prev) > rank_key(nxt):
            return False
    return True

